(function () {
'use strict';
const canvas = document.getElementById('particles-canvas');
if (!canvas) return;
const ctx = canvas.getContext('2d', { alpha: true });
let particles = [];
let mouse = { x: null, y: null, radius: 120 };
let animationId;
let isPageVisible = true;
document.addEventListener('visibilitychange', () => {
isPageVisible = !document.hidden;
if (isPageVisible && !animationId) animate();
});
function resize() {
canvas.width = window.innerWidth;
canvas.height = window.innerHeight;
}
let resizeTimer;
window.addEventListener('resize', () => {
clearTimeout(resizeTimer);
resizeTimer = setTimeout(() => {
resize();
initParticles();
}, 250);
});
resize();
let mouseThrottled = false;
window.addEventListener('mousemove', (e) => {
if (mouseThrottled) return;
mouseThrottled = true;
mouse.x = e.clientX;
mouse.y = e.clientY;
setTimeout(() => { mouseThrottled = false; }, 32);
}, { passive: true });
window.addEventListener('mouseout', () => {
mouse.x = null;
mouse.y = null;
}, { passive: true });
class Particle {
constructor() {
this.reset();
}
reset() {
this.x = Math.random() * canvas.width;
this.y = Math.random() * canvas.height;
this.size = Math.random() * 2 + 0.5;
this.speedX = (Math.random() - 0.5) * 0.4;
this.speedY = (Math.random() - 0.5) * 0.4;
this.opacity = Math.random() * 0.5 + 0.1;
const rand = Math.random();
if (rand < 0.6) {
this.color = `rgba(212, 25, 32, ${this.opacity})`;
} else if (rand < 0.85) {
this.color = `rgba(255, 42, 42, ${this.opacity * 0.7})`;
} else {
this.color = `rgba(200, 200, 200, ${this.opacity * 0.5})`;
}
}
update() {
this.x += this.speedX;
this.y += this.speedY;
if (mouse.x !== null && mouse.y !== null) {
const dx = this.x - mouse.x;
const dy = this.y - mouse.y;
const distSq = dx * dx + dy * dy;
const radiusSq = mouse.radius * mouse.radius;
if (distSq < radiusSq) {
const dist = Math.sqrt(distSq);
const force = (mouse.radius - dist) / mouse.radius;
const angle = Math.atan2(dy, dx);
this.x += Math.cos(angle) * force * 2;
this.y += Math.sin(angle) * force * 2;
}
}
const w = canvas.width;
const h = canvas.height;
if (this.x < 0) this.x = w;
else if (this.x > w) this.x = 0;
if (this.y < 0) this.y = h;
else if (this.y > h) this.y = 0;
}
draw() {
ctx.beginPath();
ctx.arc(this.x, this.y, this.size, 0, 6.2832);
ctx.fillStyle = this.color;
ctx.fill();
}
}
function initParticles() {
particles = [];
const count = Math.min(Math.floor((canvas.width * canvas.height) / 12000), 80);
for (let i = 0; i < count; i++) {
particles.push(new Particle());
}
}
function connectParticles() {
const len = particles.length;
const connectionDistSq = 90 * 90;
ctx.lineWidth = 0.5;
for (let i = 0; i < len; i++) {
const pi = particles[i];
for (let j = i + 1; j < len; j++) {
const pj = particles[j];
const dx = pi.x - pj.x;
const dy = pi.y - pj.y;
const distSq = dx * dx + dy * dy;
if (distSq < connectionDistSq) {
const opacity = (1 - distSq / connectionDistSq) * 0.15;
ctx.beginPath();
ctx.strokeStyle = `rgba(212, 25, 32, ${opacity})`;
ctx.moveTo(pi.x, pi.y);
ctx.lineTo(pj.x, pj.y);
ctx.stroke();
}
}
}
}
function animate() {
if (!isPageVisible) {
animationId = null;
return;
}
ctx.clearRect(0, 0, canvas.width, canvas.height);
const len = particles.length;
for (let i = 0; i < len; i++) {
particles[i].update();
particles[i].draw();
}
connectParticles();
animationId = requestAnimationFrame(animate);
}
initParticles();
animate();
const nav = document.getElementById('main-nav');
const hamburger = document.getElementById('hamburger');
const navLinks = document.getElementById('nav-links');
if (nav) {
window.addEventListener('scroll', () => {
if (window.scrollY > 50) {
nav.classList.add('scrolled');
} else {
nav.classList.remove('scrolled');
}
}, { passive: true });
}
function initAuth() {
const user = JSON.parse(localStorage.getItem('zs_user'));
const navAction = document.querySelector('.nav-action');
const heroLeft = document.querySelector('.hero-left');
if (user && user.isLoggedIn) {
if (navAction) {
navAction.innerHTML = `<div class="profile-avatar">${user.name.charAt(0).toUpperCase()}</div>`;
navAction.href = "#";
const dropdown = document.createElement('div');
dropdown.className = 'profile-dropdown';
dropdown.innerHTML = `
<div class="dropdown-header">
<p class="user-name">${user.name}</p>
<p class="user-email">${user.email || 'Member'}</p>
</div>
<ul class="dropdown-menu">
<li><a href="account"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle></svg> Profile Settings</a></li>
<li><a href="#" id="logout-btn"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"></path><polyline points="16 17 21 12 16 7"></polyline><line x1="21" y1="12" x2="9" y2="12"></line></svg> Logout</a></li>
</ul>
`;
navAction.parentElement.appendChild(dropdown);
navAction.addEventListener('click', (e) => {
e.preventDefault();
dropdown.classList.toggle('active');
});
document.addEventListener('click', (e) => {
if (!navAction.contains(e.target) && !dropdown.contains(e.target)) {
dropdown.classList.remove('active');
}
});
document.getElementById('logout-btn').addEventListener('click', (e) => {
e.preventDefault();
localStorage.removeItem('zs_user');
window.location.reload();
});
}
if (heroLeft) {
const welcome = document.createElement('div');
welcome.className = 'welcome-toast fade-in';
welcome.innerHTML = `Welcome back, <span class="red">${user.name.split(' ')[0]}</span>`;
heroLeft.insertBefore(welcome, heroLeft.firstChild);
}
}
}
initAuth();
if (hamburger && navLinks) {
hamburger.addEventListener('click', () => {
hamburger.classList.toggle('active');
navLinks.classList.toggle('open');
document.body.style.overflow = navLinks.classList.contains('open') ? 'hidden' : '';
});
navLinks.querySelectorAll('.nav-link').forEach(link => {
link.addEventListener('click', () => {
hamburger.classList.remove('active');
navLinks.classList.remove('open');
document.body.style.overflow = '';
});
});
}
function highlightActiveLink() {
const path = window.location.pathname.replace(/\/+$/, '');
const links = document.querySelectorAll('.nav-link');
links.forEach(link => {
try {
const hrefAttr = link.getAttribute('href');
if (!hrefAttr) return;
const url = new URL(hrefAttr, window.location.origin);
const linkPath = url.pathname.replace(/\/+$/, '');
if (linkPath === path || (linkPath === '/home' && (path === '' || path === '/'))) {
link.classList.add('active');
link.setAttribute('aria-current', 'page');
} else {
link.classList.remove('active');
link.removeAttribute('aria-current');
}
} catch (e) {
const href = link.getAttribute('href');
if (href === 'home' || href === '/home' || href === '/') {
if (path === '' || path === '/' || path === '/home') {
link.classList.add('active');
}
}
}
});
}
highlightActiveLink();
function initSyndicateModal() {
        if (!document.getElementById('syndicate-modal')) {
            const modalOverlay = document.createElement('div');
            modalOverlay.id = 'syndicate-modal';
            modalOverlay.className = 'zs-modal-overlay';
            modalOverlay.innerHTML = `
                <div class="zs-modal-card">
                    <button class="zs-modal-close" id="close-syndicate-modal" aria-label="Close modal">&times;</button>
                    <span class="zs-cta-eyebrow">THE INNER CIRCLE</span>
                    <h2 class="zs-cta-title" style="font-size: clamp(1.8rem, 4vw, 2.8rem); margin-bottom: 16px; font-family: 'Anton', sans-serif; letter-spacing: 1.5px; text-transform: uppercase;">GET INSIDE <span style="color: #d41920; text-shadow: 0 0 15px rgba(212,25,32,0.35);">BEFORE THE DROP.</span></h2>
                    <p class="zs-cta-desc" style="font-size: 0.95rem; margin-bottom: 20px;">Receive exclusive access to the first chapter of ZAYLORE Studio.</p>
                    <ul class="zs-list-perks">
                        <li>First Drop Announcements</li>
                        <li>Event Invitations</li>
                        <li>Founder Updates</li>
                        <li>Behind-The-Scenes Content</li>
                        <li>Community Opportunities</li>
                    </ul>
                    <form class="zs-modal-form" id="modal-syndicate-form">
                        <div class="zs-modal-input-wrap">
                            <input type="text" id="modal-syn-name" class="zs-modal-input" placeholder="Your Name" required autocomplete="name">
                        </div>
                        <div class="zs-modal-input-wrap">
                            <input type="email" id="modal-syn-email" class="zs-modal-input" placeholder="Your Email Address" required autocomplete="email">
                        </div>
                        <button type="submit" class="zs-btn-primary zs-modal-submit" id="modal-syn-submit-btn">
                            <span>GET EARLY ACCESS</span>
                        </button>
                    </form>
                    <p class="zs-modal-privacy">By joining, you agree to our <a href="privacy" target="_blank">Privacy Policy</a>. Unsubscribe at any time.</p>
                </div>
            `;
            document.body.appendChild(modalOverlay);
        }
        const modal = document.getElementById('syndicate-modal');
        const closeBtn = document.getElementById('close-syndicate-modal');
        const form = document.getElementById('modal-syndicate-form');
        window.showSyndicateModal = function (e) {
            if (e) e.preventDefault();
            modal.classList.add('active');
            document.body.style.overflow = 'hidden';
        };
        window.hideSyndicateModal = function () {
            modal.classList.remove('active');
            document.body.style.overflow = '';
        };
        if (closeBtn) {
            closeBtn.addEventListener('click', window.hideSyndicateModal);
        }
        modal.addEventListener('click', (e) => {
            if (e.target === modal) window.hideSyndicateModal();
        });
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && modal.classList.contains('active')) {
                window.hideSyndicateModal();
            }
        });
        document.addEventListener('click', (e) => {
            const target = e.target.closest('a, button');
            if (!target) return;
            const href = target.getAttribute('href') || '';
            const text = (target.textContent || '').toUpperCase();
            if (
                target.classList.contains('trigger-syndicate-modal') ||
                href === '#syndicate-signup' ||
                href === '/#syndicate-signup' ||
                (text.includes('JOIN THE SYNDICATE') && !target.closest('#homepage-syndicate-form') && !target.closest('#syndicate-join-form') && !target.closest('#prelaunch-signup-form'))
            ) {
                e.preventDefault();
                window.showSyndicateModal();
            }
        });
        if (form) {
            form.addEventListener('submit', async (e) => {
                e.preventDefault();
                const nameInput = document.getElementById('modal-syn-name');
                const emailInput = document.getElementById('modal-syn-email');
                const submitBtn = document.getElementById('modal-syn-submit-btn');
                const name = nameInput.value.trim();
                const email = emailInput.value.trim();
                if (!name || !email) return;
                submitBtn.disabled = true;
                submitBtn.querySelector('span').textContent = 'JOINING...';
                try {
                    if (window.ZayloreDB) {
                        if (typeof window.ZayloreDB.subscribeNewsletter === 'function') {
                            await window.ZayloreDB.subscribeNewsletter(email, name);
                        } else if (typeof window.ZayloreDB.addSubscriber === 'function') {
                            await window.ZayloreDB.addSubscriber(email, 'syndicate');
                        }
                    }
                    const subs = JSON.parse(localStorage.getItem('zs_newsletter') || '[]');
                    const exists = subs.find(s => s.email.toLowerCase() === email.toLowerCase());
                    if (!exists) {
                        subs.push({
                            email: email.toLowerCase(),
                            name: name,
                            source: 'global_syndicate_modal',
                            subscribedAt: new Date().toISOString()
                        });
                        localStorage.setItem('zs_newsletter', JSON.stringify(subs));
                    }
                    showToast("WELCOME TO THE SYNDICATE. MEMBERSHIP APPROVED.", false);
                    submitBtn.querySelector('span').textContent = 'JOINED ✓';
                    submitBtn.style.background = '#00ff00';
                    submitBtn.style.borderColor = '#00ff00';
                    submitBtn.style.color = '#000000';
                    nameInput.value = '';
                    emailInput.value = '';
                    setTimeout(() => {
                        window.hideSyndicateModal();
                        submitBtn.disabled = false;
                        submitBtn.querySelector('span').textContent = 'GET EARLY ACCESS';
                        submitBtn.style.background = '';
                        submitBtn.style.borderColor = '';
                        submitBtn.style.color = '';
                    }, 2000);
                } catch (err) {
                    console.error("Failed to join syndicate modal", err);
                    showToast("Failed to join. Please try again.", true);
                    submitBtn.disabled = false;
                    submitBtn.querySelector('span').textContent = 'GET EARLY ACCESS';
                }
            });
        }
    }
    function showToast(msg, isError = true) {
        let toast = document.getElementById('zs-prod-toast');
        if (!toast) {
            toast = document.createElement('div');
            toast.id = 'zs-prod-toast';
            document.body.appendChild(toast);
        }
        toast.innerText = msg;
        toast.className = `auth-toast show ${isError ? 'error' : 'success'}`;
        setTimeout(() => {
            toast.classList.remove('show');
        }, 4000);
    }
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initSyndicateModal);
    } else {
        initSyndicateModal();
    }
})();
(function() {
let botpressLoaded = false;
function loadBotpress() {
if (botpressLoaded) return;
botpressLoaded = true;
const script = document.createElement("script");
script.src = "https://cdn.botpress.cloud/webchat/v3.6/inject.js";
script.async = true;
script.onload = () => {
if (window.botpress) {
window.botpress.init({
"botId": "0712ab3f-9d30-4ddb-88c9-62ba531226bb",
"clientId": "a3cb76b2-5c9e-48f0-852a-644c5bd0e3d0",
"configuration": {
"botName": "Zaylore Assistant",
"color": "#d41920",
"themeMode": "dark",
"website": {},
"email": {},
"phone": {},
"termsOfService": {},
"privacyPolicy": {}
}
});
}
};
document.body.appendChild(script);
}
const interactionEvents = ["mouseover", "keydown", "touchstart", "scroll"];
function triggerBotpress() {
loadBotpress();
interactionEvents.forEach(evt => window.removeEventListener(evt, triggerBotpress, { passive: true }));
}
setTimeout(loadBotpress, 4000);
interactionEvents.forEach(evt => window.addEventListener(evt, triggerBotpress, { passive: true }));
})();